static int qsearch(SearchInfo *si, int alpha, int beta) {
    Board *b = si->board;
    si->nodes++;

    if (si->stopped) return 0;
    check_time(si);
    if (si->stopped) return 0;

    if (b->ply > si->sel_depth) si->sel_depth = b->ply;

    /* Init PV length for this ply (must be before any early return) */
    si->pv_length[b->ply] = b->ply;

    if (b->ply >= MAX_PLY) return evaluate(b);

    /* Stand pat */
    int stand_pat = evaluate(b);
    if (stand_pat >= beta) return beta;
    if (stand_pat > alpha) alpha = stand_pat;

    MoveList ml;
    generate_captures(b, &ml);
    score_moves(b, &ml, MOVE_NONE, &si->sd, b->ply, MOVE_NONE);

    for (int i = 0; i < ml.count; i++) {
        pick_move(&ml, i);
        Move m = ml.moves[i];

        if (!is_move_legal(b, m)) continue;

        /* SEE pruning: skip captures with SEE < 0 */
        if (!move_is_promotion(m) && !see_ge(b, m, 0)) continue;

        /* Delta pruning: skip if capture can't raise alpha */
        if (!move_is_promotion(m)) {
            int captured = b->mailbox[move_to(m)];
            if (captured != NO_PIECE) {
                static const int piece_vals[] = { 100, 320, 330, 500, 900, 0 };
                int cap_val = piece_vals[piece_type_of(captured)];
                if (stand_pat + cap_val + 200 < alpha) continue;
            }
        }

        board_make_move(b, m);
        int score = -qsearch(si, -beta, -alpha);
        board_unmake_move(b);

        if (si->stopped) return 0;

        if (score > alpha) {
            alpha = score;
            if (score >= beta) return beta;
        }
    }

    return alpha;
}

static int quiescence(Board *board, int alpha, int beta, int ply, int hash_len, SearchState *state) {
    if ((state->nodes & 2047ULL) == 0 && should_stop(state)) {
        state->stop = 1;
        return 0;
    }
    state->nodes++;
    if (ply > state->seldepth) {
        state->seldepth = ply;
    }

    if (is_repetition(state, board->hash, hash_len, board->halfmove_clock)) {
        return 0;
    }

    int stand_pat = evaluate(board);
    if (stand_pat >= beta) {
        return beta;
    }
    if (stand_pat > alpha) {
        alpha = stand_pat;
    }

    if (ply >= MAX_PLY - 1) {
        return stand_pat;
    }

    MoveList legal_moves;
    generate_legal_moves(board, &legal_moves);

    uint32_t tt_move = 0;
    TTEntry *entry = tt_probe(board->hash);
    if (entry->key == board->hash) {
        tt_move = entry->move;
    }

    int scores[MAX_MOVES];
    init_move_scores(&legal_moves, scores, ply, tt_move, state, 1);

    for (int i = 0; i < legal_moves.count; ++i) {
        int idx = pick_next_move(&legal_moves, scores, i);
        Move move = legal_moves.moves[idx];

        if (!move_is_tactical(&move)) {
            continue;
        }
        if (move.flags & FLAG_CAPTURE) {
            int victim_value = see_piece_value(move.captured);
            if (!(move.flags & FLAG_PROMOTION) &&
                stand_pat + victim_value + DELTA_PRUNE_MARGIN < alpha) {
                continue;
            }
            if (!(move.flags & FLAG_PROMOTION) && static_exchange_eval(board, &move) < 0) {
                continue;
            }
        }

        Undo undo;
        make_move(board, move, &undo);

        int child_hash_len = hash_len;
        if (child_hash_len < MAX_HASH_HISTORY) {
            state->hash_history[child_hash_len++] = board->hash;
        }

        int score = -quiescence(board, -beta, -alpha, ply + 1, child_hash_len, state);
        unmake_move(board, &undo);

        if (state->stop) {
            return alpha;
        }

        if (score >= beta) {
            return beta;
        }
        if (score > alpha) {
            alpha = score;
        }
    }

    return alpha;
}

int Search::quiescence(int alpha, int beta, int ply) {
    if (stopped) return 0;
    nodes_++;
    check_time();
    if (stopped) return 0;

    if (ply >= MAX_PLY - 1)
        return Eval::evaluate(*pos_);

    int orig_alpha = alpha;
    bool in_check = pos_->is_in_check();

    // TT probe
    bool tt_hit;
    TTEntry* tte = TT.probe(pos_->key(), tt_hit);
    Move tt_move = tt_hit ? tte->move() : MOVE_NONE;
    int tt_value = tt_hit ? (int)tte->value : VALUE_NONE;

    // TT cutoff (not when in check — need to verify no mate)
    if (tt_hit && !in_check) {
        if ((tte->bound == BOUND_EXACT)
            || (tte->bound == BOUND_LOWER && tt_value >= beta)
            || (tte->bound == BOUND_UPPER && tt_value <= alpha))
            return tt_value;
    }

    int stand_pat;
    if (in_check) {
        stand_pat = -VALUE_INFINITE;
    } else {
        stand_pat = Eval::evaluate(*pos_);
        if (stand_pat >= beta) {
            tte->save(pos_->key(), stand_pat, BOUND_LOWER, 0, MOVE_NONE, stand_pat, TT.generation());
            return stand_pat;
        }
        if (stand_pat > alpha) alpha = stand_pat;
    }

    int best_score = stand_pat;
    Move best_qmove = MOVE_NONE;

    // In check: generate all legal moves (evasions)
    if (in_check) {
        MoveList pseudo;
        generate_moves(*pos_, pseudo);

        int move_count = 0;
        for (const auto& sm : pseudo) {
            if (!pos_->is_legal(sm.move)) continue;
            move_count++;

            StateInfo st;
            pos_->do_move(sm.move, st);
            int score = -quiescence(-beta, -alpha, ply + 1);
            pos_->undo_move(sm.move);

            if (score > best_score) {
                best_score = score;
                best_qmove = sm.move;
                if (score > alpha) {
                    alpha = score;
                    if (score >= beta) break;
                }
            }
        }

        if (move_count == 0)
            return -VALUE_MATE + ply;

        Bound bound = best_score >= beta ? BOUND_LOWER :
                      best_score > orig_alpha ? BOUND_EXACT : BOUND_UPPER;
        tte->save(pos_->key(), best_score, bound, 0, best_qmove, -VALUE_INFINITE, TT.generation());
        return best_score;
    }

    // Normal qsearch: captures only (with capture history for ordering)
    MovePicker mp(*pos_, tt_move, &capture_history_);
    Move move;

    while ((move = mp.next_move()) != MOVE_NONE) {
        // Delta pruning
        int captured_value = PieceValue[type_of(pos_->piece_on(move.to()))];
        if (move.type() == EN_PASSANT) captured_value = PieceValue[PAWN];
        if (move.type() == PROMOTION) captured_value += PieceValue[move.promotion_type()] - PieceValue[PAWN];
        if (stand_pat + captured_value + 200 < alpha)
            continue;

        if (!pos_->is_legal(move)) continue;

        StateInfo st;
        pos_->do_move(move, st);
        int score = -quiescence(-beta, -alpha, ply + 1);
        pos_->undo_move(move);

        if (score > best_score) {
            best_score = score;
            best_qmove = move;
            if (score > alpha) {
                alpha = score;
                if (score >= beta) break;
            }
        }
    }

    // TT storage
    Bound bound = best_score >= beta ? BOUND_LOWER :
                  best_score > orig_alpha ? BOUND_EXACT : BOUND_UPPER;
    tte->save(pos_->key(), best_score, bound, 0, best_qmove, stand_pat, TT.generation());
    return best_score;
}

int Searcher::quiescence(Board &b, int alpha, int beta, int ply) {
  check_time();
  if (stop_) return alpha;
  nodes_++;

  const Color us = b.side_to_move();
  const bool in_check = b.in_check(us);

  if (ply >= MaxPly - 1) {
    return in_check ? (-MateScore + ply) : eval::evaluate(b);
  }

  int stand_pat = 0;
  if (!in_check) {
    stand_pat = eval::evaluate(b);
    if (stand_pat >= beta) return beta;
    if (stand_pat > alpha) alpha = stand_pat;
  }

  auto &pseudo = move_stack_[ply];
  movegen::generate_pseudo_legal(b, pseudo);

  std::vector<Move> *moves_ptr = &pseudo;
  if (!in_check) {
    auto &caps = qmove_stack_[ply];
    caps.clear();
    caps.reserve(pseudo.size());
    for (const Move &m : pseudo) {
      if (m.flags & MF_CAPTURE) caps.push_back(m);
      else if (m.flags & MF_PROMOTION) caps.push_back(m);
    }
    moves_ptr = &caps;
  }

  auto &moves = *moves_ptr;

  // Order moves: prioritize captures/promotions by MVV-LVA, then the rest.
  std::sort(moves.begin(), moves.end(), [&](const Move &a, const Move &c) {
    const bool capA = (a.flags & MF_CAPTURE) || (a.flags & MF_PROMOTION);
    const bool capC = (c.flags & MF_CAPTURE) || (c.flags & MF_PROMOTION);
    if (capA != capC) return capA > capC;
    if (!capA) return false;
    const Piece attA = b.piece_at(a.from);
    const Piece vicA = (a.flags & MF_EN_PASSANT) ? make_piece(!us, PieceType::Pawn) : b.piece_at(a.to);
    const Piece attC = b.piece_at(c.from);
    const Piece vicC = (c.flags & MF_EN_PASSANT) ? make_piece(!us, PieceType::Pawn) : b.piece_at(c.to);
    return mvv_lva(attA, vicA) > mvv_lva(attC, vicC);
  });

  int legal = 0;
  for (const Move &m : moves) {
    int optimistic_gain = 0;
    int see_score = 0;
    bool have_see = false;

    if (!in_check) {
      const PieceType attacker_from = type_of(b.piece_at(m.from));
      PieceType attacker_to = attacker_from;
      if (m.flags & MF_PROMOTION) attacker_to = static_cast<PieceType>(m.promo);

      if (m.flags & MF_CAPTURE) {
        PieceType victim = PieceType::None;
        if (m.flags & MF_EN_PASSANT) victim = PieceType::Pawn;
        else victim = type_of(b.piece_at(m.to));
        optimistic_gain += piece_value(victim);
      }
      if (m.flags & MF_PROMOTION) {
        optimistic_gain += piece_value(attacker_to) - piece_value(PieceType::Pawn);
      }

      const int attacker_value = piece_value(attacker_to);
      if ((m.flags & MF_CAPTURE) && optimistic_gain < attacker_value) {
        have_see = true;
        see_score = see(b, m);
      }
    }

    UndoState u;
    b.make_move(m, u);
    const bool illegal = b.is_square_attacked(b.king_square(us), b.side_to_move());
    if (illegal) {
      b.unmake_move(m, u);
      continue;
    }

    const bool gives_check = b.in_check(b.side_to_move());
    if (!in_check && !gives_check) {
      // Delta pruning: if even the optimistic material swing can't raise alpha, skip.
      constexpr int kDeltaMargin = 120;
      if (stand_pat + optimistic_gain + kDeltaMargin < alpha) {
        b.unmake_move(m, u);
        continue;
      }

      // SEE pruning: skip clearly losing captures unless they give check.
      if (have_see && see_score < 0) {
        b.unmake_move(m, u);
        continue;
      }
    }
    legal++;
    const int score = -quiescence(b, -beta, -alpha, ply + 1);
    b.unmake_move(m, u);
    if (stop_) return alpha;
    if (score >= beta) return beta;
    if (score > alpha) alpha = score;
  }

  if (in_check && legal == 0) {
    return -MateScore + ply;
  }
  return alpha;
}

fn quiescence(&mut self, mut alpha: i32, beta: i32, ply: usize) -> i32 {
    self.nodes += 1;
    self.check_time();
    if self.timer.should_stop() {
        return 0;
    }

    if ply >= MAX_PLY - 1 {
        return self.eval();
    }

    let is_pv = beta - alpha > 1;
    let hash = self.board.hash;

    // TT probe in qsearch
    if let Some(entry) = self.tt.probe(hash) {
        let tt_score = self.score_from_tt(entry.score as i32, ply);
        if !is_pv {
            match entry.flag() {
                TTFlag::Exact => return tt_score,
                TTFlag::LowerBound if tt_score >= beta => return tt_score,
                TTFlag::UpperBound if tt_score <= alpha => return tt_score,
                _ => {}
            }
        }
    }

    // Stand pat
    let stand_pat = self.eval();

    if stand_pat >= beta {
        return stand_pat;
    }

    // Delta pruning: if we can't possibly raise alpha even with the best capture
    if stand_pat + 1000 < alpha {
        return stand_pat;
    }

    if stand_pat > alpha {
        alpha = stand_pat;
    }

    let original_alpha = alpha;
    let mut best_score = stand_pat;
    let mut best_move = Move::NONE;

    let mut moves = self.board.gen_captures();
    movepick::score_captures(&self.board, &mut moves);

    for i in 0..moves.len() {
        let sm = moves.pick_move(i);
        let mv = sm.mv;

        // SEE pruning: skip bad captures
        if !self.board.see(mv, 0) {
            continue;
        }

        self.board.make_move(mv);
        let score = -self.quiescence(-beta, -alpha, ply + 1);
        self.board.unmake_move(mv);

        if self.timer.should_stop() {
            return 0;
        }

        if score > best_score {
            best_score = score;
            best_move = mv;
            if score > alpha {
                alpha = score;
                if score >= beta {
                    break;
                }
            }
        }
    }

    // Store in TT
    let flag = if best_score >= beta {
        TTFlag::LowerBound
    } else if best_score > original_alpha {
        TTFlag::Exact
    } else {
        TTFlag::UpperBound
    };
    self.tt.store(
        hash,
        best_move,
        self.score_to_tt(best_score, ply) as i16,
        0,
        flag,
    );

    best_score
}

fn quiescence(&mut self, board: &Board, ply: usize, mut alpha: i32, beta: i32) -> i32 {
    self.nodes += 1;

    if (self.nodes & 2047 == 0) && self.out_of_time() {
        self.timed_out = true;
        return 0;
    }

    let stand_pat = evaluate(board);
    if stand_pat >= beta {
        return beta;
    }
    if stand_pat > alpha {
        alpha = stand_pat;
    }

    let mut moves: Vec<ChessMove> = MoveGen::new_legal(board)
        .filter(|mv| is_tactical(board, *mv))
        .collect();
    moves.sort_unstable_by(|left, right| {
        score_move(board, *right, None, ply, self.killers, self.history).cmp(&score_move(
            board,
            *left,
            None,
            ply,
            self.killers,
            self.history,
        ))
    });

    for mv in moves {
        let next_board = board.make_move_new(mv);
        let score = -self.quiescence(&next_board, ply + 1, -beta, -alpha);

        if self.timed_out {
            return 0;
        }

        if score >= beta {
            return beta;
        }
        if score > alpha {
            alpha = score;
        }
    }

    alpha
}

