private int quiescence(int alpha, int beta, int ply) {
    bumpNode();
    if (isStopped() || ply >= MAX_PLY - 1) {
        return evaluator.evaluate(board);
    }

    if (board.halfmoveClock() >= 100 || isRepetition(ply)) {
        return 0;
    }

    boolean inCheck = board.isInCheck(board.sideToMove());

    int standPat = evaluator.evaluate(board);
    if (!inCheck) {
        if (standPat >= beta) {
            return beta;
        }
        if (standPat > alpha) {
            alpha = standPat;
        }
    }

    List<Move> tacticalMoves = board.generateLegalMoves(inCheck ? false : true);
    if (tacticalMoves.isEmpty()) {
        if (inCheck) {
            return -MATE_SCORE + ply;
        }
        return inCheck ? -MATE_SCORE + ply : alpha;
    }

    sortMoves(tacticalMoves, ply, null, true);

    for (Move move : tacticalMoves) {
        if (!inCheck && !isTactical(move)) {
            continue;
        }

        Undo undo = new Undo();
        board.makeMove(move, undo);
        positionHistory[ply + 1] = board.positionKey();
        int score = -quiescence(-beta, -alpha, ply + 1);
        board.unmakeMove(move, undo);

        if (isStopped()) {
            return alpha;
        }

        if (score >= beta) {
            return beta;
        }
        if (score > alpha) {
            alpha = score;
        }
    }

    return alpha;
}

private int quiescence(int alpha, int beta, int ply) {
    if (ply >= MAX_PLY - 1) return Evaluation.evaluate(board);

    if ((info.nodes & (NODE_CHECK_INTERVAL - 1)) == 0) checkTime();
    if (info.stopped) return 0;

    info.nodes++;

    boolean inCheck = MoveGenerator.isInCheck(board);

    if (inCheck) {
        MoveList moves = MoveGenerator.generateLegalMoves(board);
        if (moves.size == 0) return -Evaluation.MATE_SCORE + ply;

        int bestScore = -Evaluation.MATE_SCORE;
        scoreCaptures(moves);
        for (int i = 0; i < moves.size; i++) {
            int move = moves.pickBest(i);
            board.makeMove(move);
            int score = -quiescence(-beta, -alpha, ply + 1);
            board.unmakeMove();
            if (info.stopped) return 0;
            if (score > bestScore) bestScore = score;
            if (score >= beta) return score;
            if (score > alpha) alpha = score;
        }
        return bestScore;
    }

    int standPat = Evaluation.evaluate(board);
    if (standPat >= beta) return standPat;
    if (standPat > alpha) alpha = standPat;

    MoveList captures = MoveGenerator.generateCaptures(board);
    scoreCaptures(captures);

    for (int i = 0; i < captures.size; i++) {
        int move = captures.pickBest(i);

        // Delta pruning: skip if capture + margin can't improve alpha
        if (!Move.isPromotion(move)) {
            int see = pieceValue(Move.captured(move));
            if (standPat + see + 200 < alpha) continue;
        }

        board.makeMove(move);
        int score = -quiescence(-beta, -alpha, ply + 1);
        board.unmakeMove();

        if (info.stopped) return 0;

        if (score >= beta) return score;
        if (score > alpha) alpha = score;
    }

    return alpha;
}

def _quiescence(self, board, alpha: int, beta: int, ply: int) -> int:
    if self._time_up():
        self.stop = True
        return 0

    self.nodes += 1

    # Mate distance pruning.
    alpha = max(alpha, -MATE + ply)
    beta = min(beta, MATE - ply - 1)
    if alpha >= beta:
        return alpha

    if board.halfmove_clock >= 100 or board.is_threefold_repetition():
        return 0

    if board.is_in_check(board.turn):
        moves = list(board.generate_pseudo_moves())
        moves = self._order_moves(board, moves, 0, ply)
        legal_found = False
        for m in moves:
            undo = board.push(m)
            moved_color = -board.turn
            king_sq = board.king_white if moved_color > 0 else board.king_black
            if board.is_attacked(king_sq, board.turn):
                board.pop(undo)
                continue
            legal_found = True
            score = -self._quiescence(board, -beta, -alpha, ply + 1)
            board.pop(undo)
            if self._time_up():
                self.stop = True
                return alpha
            if score >= beta:
                return beta
            if score > alpha:
                alpha = score
        if not legal_found:
            return -MATE + ply
        return alpha

    stand_pat = self._static_eval(board)
    if stand_pat >= beta:
        return beta
    if stand_pat > alpha:
        alpha = stand_pat

    # Only captures / promotions
    caps = []
    for m in board.generate_pseudo_moves():
        t = to_sq(m)
        if promo_piece(m) or board.squares[t] != 0 or flag(m) == FLAG_EP:
            caps.append(m)
    caps = self._order_moves(board, caps, 0, ply)

    for m in caps:
        t = to_sq(m)
        promo = promo_piece(m)
        captured_type = PAWN if flag(m) == FLAG_EP else abs(board.squares[t])
        gain = (PIECE_VALUE[captured_type] if captured_type else 0) + (
            (PIECE_VALUE[promo] - PIECE_VALUE[PAWN]) if promo else 0
        )
        if stand_pat + gain + 200 < alpha:
            continue
        undo = board.push(m)
        moved_color = -board.turn
        king_sq = board.king_white if moved_color > 0 else board.king_black
        if board.is_attacked(king_sq, board.turn):
            board.pop(undo)
            continue
        score = -self._quiescence(board, -beta, -alpha, ply + 1)
        board.pop(undo)

        if self._time_up():
            self.stop = True
            return alpha

        if score >= beta:
            return beta
        if score > alpha:
            alpha = score

    return alpha

def _quiescence(self, board: chess.Board, alpha: float, beta: float, ply: int) -> float:
    self._nodes += 1
    if (self._nodes & 1023) == 0:
        self._check_time()

    if board.is_game_over(claim_draw=True):
        return self._terminal_score(board, ply)

    stand_pat = self._evaluate_for_side(board)
    if stand_pat >= beta:
        return stand_pat
    if stand_pat > alpha:
        alpha = stand_pat

    if board.is_check():
        noisy_moves = list(board.legal_moves)
    else:
        noisy_moves = list(board.generate_legal_captures())
        for move in board.legal_moves:
            if move.promotion and move not in noisy_moves:
                noisy_moves.append(move)

    if not noisy_moves:
        return stand_pat

    noisy_moves.sort(key=lambda m: self._move_order_key(board, m, ply=ply, tt_move=None), reverse=True)

    for move in noisy_moves:
        board.push(move)
        score = -self._quiescence(board, -beta, -alpha, ply + 1)
        board.pop()

        if score >= beta:
            return score
        if score > alpha:
            alpha = score

    return alpha

def _quiescence(self, alpha: int, beta: int, ply: int, qdepth: int) -> int:
    self._check_time()
    side = self.board.side_to_move()
    in_check = self.board.is_in_check(side)

    if not in_check:
        stand_pat = self._evaluate_leaf()
        if stand_pat >= beta:
            return stand_pat
        if stand_pat > alpha:
            alpha = stand_pat
        if qdepth <= 0:
            return alpha
    elif qdepth <= -2:
        # Cap check-evasion recursion to avoid runaway paths in tactical storms.
        return self._evaluate_leaf()

    found_legal = False
    for move in self._ordered_tactical_moves(ply=ply, in_check=in_check):
        self._check_time()
        snapshot = self.board.tape[:STATE_CELLS]
        if not self.board.apply_pseudo_legal_move_checked(*move, side=side):
            self.board.tape[:STATE_CELLS] = snapshot
            continue

        found_legal = True
        try:
            score = -self._quiescence(-beta, -alpha, ply + 1, qdepth - 1)
        finally:
            self.board.tape[:STATE_CELLS] = snapshot

        if score >= beta:
            return score
        if score > alpha:
            alpha = score

    if in_check and not found_legal:
        self.nodes += 1
        return -MATE_SCORE + ply
    return alpha

fn quiescence(&mut self, mut alpha: i32, beta: i32, ply: usize) -> i32 {
    if ply >= MAX_PLY - 1 {
        return evaluation::evaluate(&self.board);
    }

    if (self.info.nodes & (NODE_CHECK_INTERVAL - 1)) == 0 {
        self.check_time();
    }
    if self.info.stopped {
        return 0;
    }

    self.info.nodes += 1;

    let in_check = move_generator::is_in_check(&self.board);

    if in_check {
        let mut moves = move_generator::generate_legal_moves(&self.board);
        if moves.size == 0 {
            return -evaluation::MATE_SCORE + ply as i32;
        }

        let mut best_score = -evaluation::MATE_SCORE;
        self.score_captures(&mut moves);
        for i in 0..moves.size {
            let mv = moves.pick_best(i);
            self.board.make_move(mv);
            let score = -self.quiescence(-beta, -alpha, ply + 1);
            self.board.unmake_move();
            if self.info.stopped {
                return 0;
            }
            if score > best_score {
                best_score = score;
            }
            if score >= beta {
                return score;
            }
            if score > alpha {
                alpha = score;
            }
        }
        return best_score;
    }

    let stand_pat = evaluation::evaluate(&self.board);
    if stand_pat >= beta {
        return stand_pat;
    }
    if stand_pat > alpha {
        alpha = stand_pat;
    }

    let mut captures = move_generator::generate_captures(&self.board);
    self.score_captures(&mut captures);

    for i in 0..captures.size {
        let mv = captures.pick_best(i);

        if !move_data::is_promotion(mv) {
            let see = piece_value(move_data::captured(mv));
            if stand_pat + see + 200 < alpha {
                continue;
            }
        }

        self.board.make_move(mv);
        let score = -self.quiescence(-beta, -alpha, ply + 1);
        self.board.unmake_move();

        if self.info.stopped {
            return 0;
        }

        if score >= beta {
            return score;
        }
        if score > alpha {
            alpha = score;
        }
    }

    alpha
}

int quiescence(Position& pos, int alpha, int beta, int ply, SearchState& ss) {
  check_time(ss);
  if (ss.stopped) {
    return evaluate(pos);
  }
  if (ply >= 63) {
    return evaluate(pos);
  }
  if (pos.halfmove >= 100 || is_repetition(ss, pos.hash)) {
    return 0;
  }

  ss.nodes++;
  const bool in_check_now = in_check(pos, pos.stm, ss.cfg);
  const SearchPolicy& sp = ss.cfg.search_policy;

  int stand = -INF;
  if (!in_check_now) {
    stand = evaluate(pos);
    if (stand >= beta) {
      return beta;
    }
    if (stand > alpha) {
      alpha = stand;
    }
  }

  MoveList legal;
  gen_legal(pos, legal, ss.cfg);
  if (legal.len == 0) {
    return in_check_now ? (-MATE + ply) : 0;
  }

  struct QMove {
    int score = 0;
    Move move{};
  };
  std::vector<QMove> ordered;
  ordered.reserve(legal.len);

  for (std::uint16_t i = 0; i < legal.len; ++i) {
    Move m = legal.buf[std::size_t(i)];
    const auto promo = move_promo(m);
    const bool is_capture = move_is_capture(m);
    const bool tactical = is_capture || promo.has_value();
    if (!in_check_now && !tactical) {
      continue;
    }

    int order_score = 0;
    if (is_capture) {
      const int see = static_exchange_eval(pos, m);
      if (!in_check_now && see < sp.qsearch_capture_see_prune) {
        continue;
      }
      if (!in_check_now) {
        // Delta pruning for obviously insufficient captures.
        const int to = int(move_to(m));
        const int cap_sq = (m.raw & MOVE_FLAG_EP) ? (pos.stm == Color::White ? to - 8 : to + 8) : to;
        const std::int8_t victim_pc = (cap_sq >= 0 && cap_sq < 64) ? pos.board[std::size_t(cap_sq)] : 0;
        const int victim_value = victim_pc == 0 ? 0 : PIECE_VALUE[std::size_t(piece_to_index(victim_pc))];
        int promo_bonus = 0;
        if (promo.has_value()) {
          promo_bonus = std::max(0, piece_value_of(promo.value()) - PIECE_VALUE[std::size_t(Piece::Pawn)]);
        }
        const int optimistic = std::max(victim_value + promo_bonus, see);
        if (stand + optimistic + sp.qsearch_delta_margin < alpha) {
          continue;
        }
      }
      order_score += 100'000 + (16 * see) + capture_gain_estimate(pos, m);
    } else if (promo.has_value()) {
      if (!in_check_now) {
        const int promo_gain = std::max(0, piece_value_of(promo.value()) - PIECE_VALUE[std::size_t(Piece::Pawn)]);
        if (stand + promo_gain + sp.qsearch_delta_margin < alpha) {
          continue;
        }
      }
      order_score += 90'000 + piece_value_of(promo.value());
    } else {
      const int from = int(move_from(m));
      const int to = int(move_to(m));
      order_score += ss.history[std::size_t(from)][std::size_t(to)];
    }
    ordered.push_back(QMove{order_score, m});
  }

  std::sort(ordered.begin(), ordered.end(), [](const QMove& a, const QMove& b) {
    return a.score > b.score;
  });

  for (const QMove& qm : ordered) {
    Move m = qm.move;

    Undo u;
    make(pos, m, u, ss.cfg);
    if (ss.hash_size < int(ss.hash_stack.size())) {
      ss.hash_stack[std::size_t(ss.hash_size++)] = pos.hash;
    }
    int score = -quiescence(pos, -beta, -alpha, ply + 1, ss);
    if (ss.hash_size > 0) {
      ss.hash_size--;
    }
    unmake(pos, m, u, ss.cfg);

    if (ss.stopped) {
      return alpha;
    }

    if (score >= beta) {
      return beta;
    }
    if (score > alpha) {
      alpha = score;
    }
  }

  return alpha;
}
